    72|function backendBaseUrl(): string {
    73|  return getDirectApiBaseUrl().replace(/\/+$/, '');
    74|}
    75|
    76|async function parseResponse(response: Response): Promise<unknown> {
    77|  const text = await response.text();
    78|  if (!text) return null;
    79|  try {
    80|    return JSON.parse(text) as unknown;
    81|  } catch {
    82|    return { error: text.slice(0, 300) };
    83|  }
