    86|function readRecord(value: unknown): Record<string, unknown> {
    87|  return value && typeof value === 'object' && !Array.isArray(value) ? (value as Record<string, unknown>) : {};
    88|}
    89|
    90|function readError(payload: unknown, fallback: string): string {
    91|  const record = readRecord(payload);
    92|  return typeof record.error === 'string' && record.error.trim() ? record.error.trim() : fallback;
    93|}
