    95|async function ownerFetch(path: string, init: RequestInit = {}): Promise<unknown> {
    96|  const accessToken = await getIVXAccessToken();
    97|  if (!accessToken) {
    98|    throw new Error('Owner session token unavailable. Sign in again.');
    99|  }
   100|  const response = await fetch(`${backendBaseUrl()}${path}`, {
   101|    ...init,
   102|    headers: {
   103|      Accept: 'application/json',
   104|      'Content-Type': 'application/json',
   105|      Authorization: `Bearer ${accessToken}`,
   106|      ...(init.headers ?? {}),
   107|    },
   108|  });
   109|  const payload = await parseResponse(response);
   110|  if (!response.ok) {
   111|    throw new Error(readError(payload, `IVX rork-independence request failed with HTTP ${response.status}.`));
   112|  }
   113|  return payload;
