import { watch, readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { join, dirname } from 'path';
import { execFileSync } from 'child_process';
import { getSyncPaths, toSyncRelativePath } from './sync-paths.mjs';

